    "name": "popular-web-designs",
    "slug": "popular-web-designs",
    "category": "creative",
    "description": "54 real design systems (Stripe, Linear, Vercel) as HTML/CSS.",
    "version": "1.0.0",
    "author": "Hermes Agent + Teknium (design systems sourced from VoltAgent/awesome-design-md)",
    "license": "MIT",
    "platforms": [],
